// Notiz-App mit localStorage
class NotesApp {
    constructor() {
        this.notesKey = 'notes-app-data';
        this.notesContainer = document.getElementById('notes-container');
        this.noteTitleInput = document.getElementById('note-title');
        this.noteContentInput = document.getElementById('note-content');
        this.addNoteBtn = document.getElementById('add-note');
        this.clearAllBtn = document.getElementById('clear-all');
        this.noteCountSpan = document.getElementById('note-count');
        this.storageInfoSpan = document.getElementById('storage-info');

        this.notes = this.loadNotes();
        this.init();
    }

    // Initialisierung der App
    init() {
        // Event-Listener hinzufügen
        this.addNoteBtn.addEventListener('click', () => this.addNote());
        this.clearAllBtn.addEventListener('click', () => this.clearAllNotes());

        // Enter-Taste in den Input-Feldern unterstützen
        this.noteTitleInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                e.preventDefault();
                this.noteContentInput.focus();
            }
        });

        this.noteContentInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                this.addNote();
            }
        });

        // Notes aus localStorage laden und anzeigen
        this.renderNotes();
        this.updateNoteCount();
        this.checkStorageSupport();
    }

    // Notizen aus localStorage laden
    loadNotes() {
        try {
            const storedNotes = localStorage.getItem(this.notesKey);
            if (storedNotes) {
                return JSON.parse(storedNotes);
            }
        } catch (error) {
            console.error('Fehler beim Laden der Notizen:', error);
            this.showStorageError();
        }
        return [];
    }

    // Notizen in localStorage speichern
    saveNotes() {
        try {
            localStorage.setItem(this.notesKey, JSON.stringify(this.notes));
            this.updateNoteCount();
            return true;
        } catch (error) {
            console.error('Fehler beim Speichern der Notizen:', error);
            this.showStorageError();
            return false;
        }
    }

    // Neue Notiz hinzufügen
    addNote() {
        const title = this.noteTitleInput.value.trim();
        const content = this.noteContentInput.value.trim();

        if (!content) {
            this.showNotification('Bitte geben Sie Inhalt für die Notiz ein!', 'warning');
            this.noteContentInput.focus();
            return;
        }

        if (!title) {
            this.showNotification('Notiz ohne Titel hinzugefügt. Sie können später einen Titel hinzufügen.', 'info');
        }

        const note = {
            id: Date.now(),
            title: title || 'Ohne Titel',
            content: content,
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString()
        };

        this.notes.unshift(note); // Neue Notiz ans Anfang der Liste
        this.saveNotes();
        this.renderNotes();

        // Eingabefelder zurücksetzen
        this.noteTitleInput.value = '';
        this.noteContentInput.value = '';
        this.noteTitleInput.focus();

        this.showNotification('Notiz erfolgreich hinzugefügt!', 'success');
    }

    // Notiz bearbeiten
    editNote(id) {
        const noteIndex = this.notes.findIndex(note => note.id === id);
        if (noteIndex === -1) return;

        const note = this.notes[noteIndex];

        // Eingabefelder mit Notizinhalt füllen
        this.noteTitleInput.value = note.title === 'Ohne Titel' ? '' : note.title;
        this.noteContentInput.value = note.content;

        // Notiz löschen (wird neu erstellt)
        this.notes.splice(noteIndex, 1);
        this.saveNotes();
        this.renderNotes();

        this.showNotification('Notiz zum Bearbeiten geladen.', 'info');
        this.noteContentInput.focus();
    }

    // Notiz löschen
    deleteNote(id) {
        if (!confirm('Möchten Sie diese Notiz wirklich löschen?')) {
            return;
        }

        const noteIndex = this.notes.findIndex(note => note.id === id);
        if (noteIndex !== -1) {
            this.notes.splice(noteIndex, 1);
            this.saveNotes();
            this.renderNotes();
            this.showNotification('Notiz erfolgreich gelöscht!', 'success');
        }
    }

    // Alle Notizen löschen
    clearAllNotes() {
        if (this.notes.length === 0) {
            this.showNotification('Es sind keine Notizen zum Löschen vorhanden.', 'info');
            return;
        }

        if (!confirm(`Möchten Sie wirklich alle ${this.notes.length} Notizen löschen? Diese Aktion kann nicht rückgängig gemacht werden.`)) {
            return;
        }

        this.notes = [];
        this.saveNotes();
        this.renderNotes();
        this.showNotification('Alle Notizen wurden gelöscht.', 'success');
    }

    // Notizen rendern
    renderNotes() {
        if (this.notes.length === 0) {
            this.notesContainer.innerHTML = `
                <div class="empty-state">
                    <i class="fas fa-clipboard-list fa-3x"></i>
                    <p>Noch keine Notizen vorhanden</p>
                    <p class="hint">Beginne mit dem Erstellen deiner ersten Notiz!</p>
                </div>
            `;
            return;
        }

        let notesHTML = '';

        this.notes.forEach(note => {
            const date = new Date(note.createdAt);
            const formattedDate = date.toLocaleDateString('de-DE', {
                day: '2-digit',
                month: '2-digit',
                year: 'numeric',
                hour: '2-digit',
                minute: '2-digit'
            });

            // Kürzen von langen Inhalten für die Vorschau
            const previewContent = note.content.length > 150 
                ? note.content.substring(0, 150) + '...' 
                : note.content;

            notesHTML += `
                <div class="note-card" data-id="${note.id}">
                    <div class="note-header">
                        <h3 class="note-title">${this.escapeHtml(note.title)}</h3>
                        <span class="note-date">${formattedDate}</span>
                    </div>
                    <div class="note-content">${this.escapeHtml(previewContent)}</div>
                    <div class="note-actions">
                        <button class="btn btn-success btn-sm edit-btn" data-id="${note.id}">
                            <i class="fas fa-edit"></i> Bearbeiten
                        </button>
                        <button class="btn btn-danger btn-sm delete-btn" data-id="${note.id}">
                            <i class="fas fa-trash"></i> Löschen
                        </button>
                    </div>
                </div>
            `;
        });

        this.notesContainer.innerHTML = notesHTML;

        // Event-Listener für Bearbeiten/Löschen Buttons hinzufügen
        this.addNoteEventListeners();
    }

    // Event-Listener für Notizaktionen hinzufügen
    addNoteEventListeners() {
        document.querySelectorAll('.edit-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const id = parseInt(e.target.closest('.edit-btn').dataset.id);
                this.editNote(id);
            });
        });

        document.querySelectorAll('.delete-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const id = parseInt(e.target.closest('.delete-btn').dataset.id);
                this.deleteNote(id);
            });
        });
    }

    // Notizzähler aktualisieren
    updateNoteCount() {
        const count = this.notes.length;
        this.noteCountSpan.textContent = `${count} ${count === 1 ? 'Notiz' : 'Notizen'} gespeichert`;

        // Speicherplatz-Anzeige
        const usedStorage = this.getUsedStorage();
        this.storageInfoSpan.title = `${usedStorage} KB verwendet`;
    }

    // Verwendeten Speicherplatz berechnen
    getUsedStorage() {
        try {
            const data = JSON.stringify(this.notes);
            return (data.length / 1024).toFixed(2);
        } catch (error) {
            return '0';
        }
    }

    // Storage-Support prüfen
    checkStorageSupport() {
        if (typeof(Storage) === 'undefined') {
            this.storageInfoSpan.textContent = 'localStorage nicht verfügbar';
            this.storageInfoSpan.style.color = '#e74c3c';
            return false;
        }
        return true;
    }

    // Benachrichtigung anzeigen
    showNotification(message, type = 'info') {
        // Alte Benachrichtigung entfernen
        const oldNotification = document.querySelector('.notification');
        if (oldNotification) {
            oldNotification.remove();
        }

        const notification = document.createElement('div');
        notification.className = `notification notification-${type}`;
        notification.innerHTML = `
            <i class="fas ${this.getNotificationIcon(type)}"></i>
            <span>${message}</span>
            <button class="notification-close">&times;</button>
        `;

        // Styling für Benachrichtigung
        notification.style.cssText = `
            position: fixed;
            top: 20px;
            right: 20px;
            background-color: ${this.getNotificationColor(type)};
            color: white;
            padding: 15px 20px;
            border-radius: 8px;
            box-shadow: 0 5px 15px rgba(0,0,0,0.2);
            display: flex;
            align-items: center;
            gap: 10px;
            z-index: 1000;
            animation: fadeIn 0.3s ease-out;
            max-width: 400px;
        `;

        document.body.appendChild(notification);

        // Close-Button Event
        notification.querySelector('.notification-close').addEventListener('click', () => {
            notification.remove();
        });

        // Automatisches Entfernen nach 5 Sekunden
        setTimeout(() => {
            if (notification.parentNode) {
                notification.style.opacity = '0';
                notification.style.transition = 'opacity 0.3s';
                setTimeout(() => {
                    if (notification.parentNode) {
                        notification.remove();
                    }
                }, 300);
            }
        }, 5000);
    }

    // Icon für Benachrichtigungstyp
    getNotificationIcon(type) {
        const icons = {
            success: 'fa-check-circle',
            warning: 'fa-exclamation-triangle',
            info: 'fa-info-circle',
            error: 'fa-times-circle'
        };
        return icons[type] || 'fa-info-circle';
    }

    // Farbe für Benachrichtigungstyp
    getNotificationColor(type) {
        const colors = {
            success: '#27ae60',
            warning: '#f39c12',
            info: '#3498db',
            error: '#e74c3c'
        };
        return colors[type] || '#3498db';
    }

    // Storage-Fehler anzeigen
    showStorageError() {
        this.storageInfoSpan.textContent = 'localStorage-Fehler';
        this.storageInfoSpan.style.color = '#e74c3c';
        this.showNotification('Fehler beim Zugriff auf localStorage. Daten werden möglicherweise nicht gespeichert.', 'error');
    }

    // HTML-Escape für sichere Ausgabe
    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

