            `;
            return;
        }

        let notesHTML = '';

        this.notes.forEach(note => {
            const date = new Date(note.createdAt);
            const formattedDate = date.toLocaleDateString('de-DE', {
                day: '2-digit',
                month: '2-digit',
                year: 'numeric',
                hour: '2-digit',
                minute: '2-digit'
            });

            // Kürzen von langen Inhalten für die Vorschau
            const previewContent = note.content.length > 150 
                ? note.content.substring(0, 150) + '...' 
                : note.content;

            notesHTML += `
                <div class="note-card" data-id="${note.id}">
                    <div class="note-header">
                        <h3 class="note-title">${this.escapeHtml(note.title)}</h3>
                        <span class="note-date">${formattedDate}</span>
                    </div>
                    <div class="note-content">${this.escapeHtml(previewContent)}</div>
                    <div class="note-actions">
                        <button class="btn btn-success btn-sm edit-btn" data-id="${note.id}">
                            <i class="fas fa-edit"></i> Bearbeiten
                        </button>
                        <button class="btn btn-danger btn-sm delete-btn" data-id="${note.id}">
                            <i class="fas fa-trash"></i> Löschen
                        </button>
                    </div>
                </div>
            `;
        });

        this.notesContainer.innerHTML = notesHTML;

        // Event-Listener für Bearbeiten/Löschen Buttons hinzufügen
        this.addNoteEventListeners();
    }

    // Event-Listener für Notizaktionen hinzufügen
    addNoteEventListeners() {
        document.querySelectorAll('.edit-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const id = parseInt(e.target.closest('.edit-btn').dataset.id);
                this.editNote(id);
            });
        });

        document.querySelectorAll('.delete-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const id = parseInt(e.target.closest('.delete-btn').dataset.id);
                this.deleteNote(id);
            });
        });
    }

    // Notizzähler aktualisieren
    updateNoteCount() {
        const count = this.notes.length;
        this.noteCountSpan.textContent = `${count} ${count === 1 ? 'Notiz' : 'Notizen'} gespeichert`;

        // Speicherplatz-Anzeige
        const usedStorage = this.getUsedStorage();
        this.storageInfoSpan.title = `${usedStorage} KB verwendet`;
    }

    // Verwendeten Speicherplatz berechnen
    getUsedStorage() {
        try {
            const data = JSON.stringify(this.notes);
            return (data.length / 1024).toFixed(2);
        } catch (error) {
            return '0';
        }
    }

    // Storage-Support prüfen
    checkStorageSupport() {
        if (typeof(Storage) === 'undefined') {
            this.storageInfoSpan.textContent = 'localStorage nicht verfügbar';
            this.storageInfoSpan.style.color = '#e74c3c';
            return false;
        }
        return true;
    }

    // Benachrichtigung anzeigen
    showNotification(message, type = 'info') {
        // Alte Benachrichtigung entfernen
        const oldNotification = document.querySelector('.notification');
        if (oldNotification) {
            oldNotification.remove();
        }

        const notification = document.createElement('div');
        notification.className = `notification notification-${type}`;
        notification.innerHTML = `
            <i class="fas ${this.getNotificationIcon(type)}"></i>
            <span>${message}</span>
            <button class="notification-close">&times;</button>
        `;

        // Styling für Benachrichtigung
        notification.style.cssText = `
            position: fixed;
            top: 20px;
            right: 20px;
            background-color: ${this.getNotificationColor(type)};
            color: white;
            padding: 15px 20px;
            border-radius: 8px;
            box-shadow: 0 5px 15px rgba(0,0,0,0.2);
            display: flex;
            align-items: center;
            gap: 10px;
            z-index: 1000;
            animation: fadeIn 0.3s ease-out;
            max-width: 400px;
        `;

        document.body.appendChild(notification);

        // Close-Button Event
        notification.querySelector('.notification-close').addEventListener('click', () => {
            notification.remove();
        });

        // Automatisches Entfernen nach 5 Sekunden
        setTimeout(() => {
            if (notification.parentNode) {
                notification.style.opacity = '0';
                notification.style.transition = 'opacity 0.3s';
                setTimeout(() => {
                    if (notification.parentNode) {
                        notification.remove();
                    }
                }, 300);
            }
        }, 5000);
    }

    // Icon für Benachrichtigungstyp
    getNotificationIcon(type) {
        const icons = {
            success: 'fa-check-circle',
            warning: 'fa-exclamation-triangle',
            info: 'fa-info-circle',
            error: 'fa-times-circle'
        };
        return icons[type] || 'fa-info-circle';
    }

    // Farbe für Benachrichtigungstyp
    getNotificationColor(type) {
        const colors = {
            success: '#27ae60',
            warning: '#f39c12',
            info: '#3498db',
            error: '#e74c3c'
        };
        return colors[type] || '#3498db';
    }

    // Storage-Fehler anzeigen
    showStorageError() {
        this.storageInfoSpan.textContent = 'localStorage-Fehler';
        this.storageInfoSpan.style.color = '#e74c3c';
        this.showNotification('Fehler beim Zugriff auf localStorage. Daten werden möglicherweise nicht gespeichert.', 'error');
    }

    // HTML-Escape für sichere Ausgabe
    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

